#include <stdio.h>
#include <stdlib.h>
#include <openssl/ec.h>

int main() {
 // Generate a random private key
 EC_KEY *private_key = EC_KEY_new_by_curve_name(NID_secp256k1);
 EC_KEY_generate_key(private_key);

 // Derive the public key from the private key
 EC_POINT *public_key = EC_POINT_new(EC_KEY_get0_group(private_key));
 EC_POINT_mul(EC_KEY_get0_group(private_key), public_key, EC_KEY_get0_private_key(private_key), NULL, NULL, 0);

 // Print the public and private keys
 printf("Public Key: %s\n", EC_POINT_point2hex(EC_KEY_get0_group(private_key), public_key, POINT_CONVERSION_UNCOMPRESSED, NULL));
 printf("Private Key: %s\n", BN_bn2hex(EC_KEY_get0_private_key(private_key)));

 return 0;
}
